+
+fn parseJsonU64(line: []const u8, key: []const u8) !u64 {
+    const needle = try std.fmt.allocPrint(std.heap.page_allocator, "\"{s}\":", .{key});
+    defer std.heap.page_allocator.free(needle);
+
+    const idx = std.mem.indexOf(u8, line, needle) orelse return error.KeyNotFound;
+    const start = idx + needle.len;
+
+    var end = start;
+    while (end < line.len and line[end] >= '0' and line[end] <= '9') {
+        end += 1;
+    }
+
+    if (end == start) return error.InvalidNumber;
+    return try std.fmt.parseInt(u64, line[start..end], 10);
+}
+
+fn parseJsonString(line: []const u8, key: []const u8) ![]u8 {
+    const needle = try std.fmt.allocPrint(std.heap.page_allocator, "\"{s}\":\"", .{key});
+    defer std.heap.page_allocator.free(needle);
+
+    const idx = std.mem.indexOf(u8, line, needle) orelse return error.KeyNotFound;
+    const start = idx + needle.len;
+
+    // Find closing quote (handle escaped quotes)
+    var end = start;
+    while (end < line.len) {
+        if (line[end] == '"' and (end == start or line[end - 1] != '\\')) {
+            break;
+        }
+        end += 1;
+    }
+
+    if (end >= line.len) return error.UnterminatedString;
+
+    // Unescape the string
+    return try unescapeJson(std.heap.page_allocator, line[start..end]);
+}
+
+fn unescapeJson(allocator: std.mem.Allocator, s: []const u8) ![]u8 {
+    var result = try std.ArrayList(u8).initCapacity(allocator, s.len);
+    defer result.deinit(allocator);
+
+    var i: usize = 0;
+    while (i < s.len) {
+        if (s[i] == '\\' and i + 1 < s.len) {
+            switch (s[i + 1]) {
+                '"' => try result.append(allocator, '"'),
+                '\\' => try result.append(allocator, '\\'),
+                'n' => try result.append(allocator, '\n'),
+                'r' => try result.append(allocator, '\r'),
+                't' => try result.append(allocator, '\t'),
+                else => {
+                    try result.append(allocator, s[i]);
+                    try result.append(allocator, s[i + 1]);
+                },
+            }
+            i += 2;
+        } else {
+            try result.append(allocator, s[i]);
+            i += 1;
+        }
+    }
+
+    return result.toOwnedSlice(allocator);
+}

