+const std = @import("std");
+const ConversationLogger = @import("conversation_logger.zig").ConversationLogger;
+const ConversationEntry = @import("conversation_logger.zig").ConversationEntry;
+const lora_trainer = @import("lora_trainer.zig");
+const TrainingExample = lora_trainer.TrainingExample;
+const logger = @import("logger.zig");
+
+/// Hippocampus state machine for memory consolidation
+pub const HippocampusState = enum(u8) {
+    awake, // Normal operation, processing requests
+    drowsy, // Idle detected, preparing data
+    dreaming, // Training in progress
+};
+
+/// Hippocampus: Automatic memory consolidation via LoRA training
+///
+/// When the system is idle, the hippocampus "sleeps" and consolidates
+/// recent conversations into a LoRA adapter, implementing event sourcing
+/// pattern where training is the "reduce" function over conversation history.
+pub const Hippocampus = struct {
+    allocator: std.mem.Allocator,
+    state: std.atomic.Value(HippocampusState),
+
+    // Dependencies
+    conversation_logger: *ConversationLogger,
+    model_path: []const u8,
+
+    // Event sourcing watermark
+    last_consolidated_event_id: u64,
+
+    // Training config
+    adapter_name: []const u8, // e.g., "long_term_memory"
+    replay_buffer_ratio: f32, // 0.1 = 10% old memories
+    min_new_events_for_training: usize, // Don't train unless N new events
+
+    // Thread management
+    training_thread: ?std.Thread,
+    training_error: ?anyerror,
+
+    // Callbacks
+    on_training_complete: ?*const fn (bool) void,
+
+    pub fn init(
+        allocator: std.mem.Allocator,
+        conversation_logger: *ConversationLogger,
+        model_path: []const u8,
+    ) !Hippocampus {
+        return Hippocampus{
+            .allocator = allocator,
+            .state = std.atomic.Value(HippocampusState).init(.awake),
+            .conversation_logger = conversation_logger,
+            .model_path = model_path,
+            .last_consolidated_event_id = 0,
+            .adapter_name = "long_term_memory",
+            .replay_buffer_ratio = 0.1,
+            .min_new_events_for_training = 10,
+            .training_thread = null,
+            .training_error = null,
+            .on_training_complete = null,
+        };
+    }
+
+    pub fn deinit(self: *Hippocampus) void {
+        // Wait for any running training to complete
+        if (self.training_thread) |thread| {
+            self.state.store(.awake, .monotonic); // Signal interrupt
+            thread.join();
+        }
+    }
+
+    pub fn isDreaming(self: *const Hippocampus) bool {
+        return self.state.load(.monotonic) == .dreaming;
+    }
+
+    pub fn isAwake(self: *const Hippocampus) bool {
+        return self.state.load(.monotonic) == .awake;
+    }
+
+    /// Try to enter sleep cycle if enough new events have accumulated
+    pub fn trySleep(self: *Hippocampus) !void {
+        // Only transition from awake to drowsy/dreaming
+        const current = self.state.load(.monotonic);
+        if (current != .awake) return;
+
+        // 1. Check if there are new events to consolidate
+        const latest_event = try self.conversation_logger.getLatestEventId();
+        if (latest_event <= self.last_consolidated_event_id) return;
+
+        const new_events = latest_event - self.last_consolidated_event_id;
+        if (new_events < self.min_new_events_for_training) {
+            logger.debug("Only {d} new events, need {d} for training", .{
+                new_events,
+                self.min_new_events_for_training,
+            });
+            return;
+        }
+
+        // 2. Transition to drowsy (preparing)
+        self.state.store(.drowsy, .monotonic);
+        logger.info("Hippocampus: Entering sleep cycle ({d} new events)", .{new_events});
+
+        // 3. Spawn training thread
+        self.training_thread = try std.Thread.spawn(.{}, dreamingEntryPoint, .{self});
+    }
+
+    /// Background thread entry point for training
+    fn dreamingEntryPoint(self: *Hippocampus) void {
+        self.state.store(.dreaming, .monotonic);
+
+        const success = self.runConsolidation() catch |err| blk: {
+            logger.err("Consolidation failed: {}", .{err});
+            self.training_error = err;
+            break :blk false;
+        };
+
+        // Cleanup and notify
+        self.state.store(.awake, .monotonic);
+        self.training_thread = null;
+
+        if (self.on_training_complete) |callback| {
+            callback(success);
+        }
+    }
+
+    /// Run the memory consolidation process
+    fn runConsolidation(self: *Hippocampus) !bool {
+        // 1. Fetch unconsolidated events (delta)
+        const new_events = try self.conversation_logger.fetchUnconsolidated(1000);
+        defer {
+            for (new_events) |*e| e.deinit(self.allocator);
+            self.allocator.free(new_events);
+        }
+
+        if (new_events.len == 0) return false;
+
+        logger.info("Consolidating {d} unconsolidated events", .{new_events.len});
+
+        // 2. Fetch replay buffer (random old memories to prevent forgetting)
+        const replay_count = @max(1, @as(usize, @intFromFloat(
+            @as(f32, @floatFromInt(new_events.len)) * self.replay_buffer_ratio,
+        )));
+        const replay_events = try self.conversation_logger.sampleConsolidated(replay_count);
+        defer {
+            for (replay_events) |*e| e.deinit(self.allocator);
+            self.allocator.free(replay_events);
+        }
+
+        logger.info("Including {d} replay buffer events for anti-forgetting", .{replay_events.len});
+
+        // 3. Format training data
+        const training_examples = try self.formatTrainingData(new_events, replay_events);
+        defer {
+            for (training_examples) |*ex| ex.deinit(self.allocator);
+            self.allocator.free(training_examples);
+        }
+
+        // 4. Check for interrupt before training
+        if (self.state.load(.monotonic) != .dreaming) {
+            logger.info("Sleep interrupted before training", .{});
+            return false;
+        }
+
+        // 5. Determine adapter path
+        const adapter_path = try self.getAdapterPath();
+        defer self.allocator.free(adapter_path);
+
+        const existing_adapter = self.getExistingAdapterPath() catch null;
+        defer if (existing_adapter) |path| self.allocator.free(path);
+
+        // 6. Create interrupt flag
+        var interrupt_flag = std.atomic.Value(bool).init(true);
+
+        // 7. Train!
+        logger.info("Starting memory consolidation training...", .{});
+        lora_trainer.train(self.allocator, .{
+            .model_path = self.model_path,
+            .output_path = adapter_path,
+            .resume_adapter_path = existing_adapter,
+            .training_examples = training_examples,
+            .interrupt_flag = &interrupt_flag,
+            .epochs = 1, // Light training
+            .learning_rate = 0.00005, // Lower LR for fine-tuning
+            .batch_size = 16,
+            .ctx_size = 1024,
+        }) catch |err| {
+            if (err == error.Interrupted) {
+                logger.info("Training was interrupted", .{});
+                return false;
+            }
+            return err;
+        };
+
+        // 8. Check for interrupt after training
+        if (self.state.load(.monotonic) != .dreaming) {
+            logger.info("Sleep interrupted during training", .{});
+            return false;
+        }
+
+        // 9. Mark events as consolidated
+        var event_ids = try self.allocator.alloc(u64, new_events.len);
+        defer self.allocator.free(event_ids);
+        for (new_events, 0..) |e, i| {
+            event_ids[i] = e.event_id;
+        }
+        try self.conversation_logger.markConsolidated(event_ids);
+
+        // 10. Update watermark
+        self.last_consolidated_event_id = new_events[new_events.len - 1].event_id;
+
+        // 11. Invalidate KV cache (trigger "morning routine")
+        try self.invalidateKVCache();
+
+        logger.info("Consolidation complete: {d} events processed", .{new_events.len});
+        return true;
+    }
+
+    /// Format conversation entries into training examples
+    fn formatTrainingData(
+        self: *Hippocampus,
+        new_events: []const ConversationEntry,
+        replay_events: []const ConversationEntry,
+    ) ![]TrainingExample {
+        var examples = try std.ArrayList(TrainingExample).initCapacity(
+            self.allocator,
